// src/components/Carrito.js
import React, { useState } from 'react';
import { ShoppingBag, Truck, Store, AlertTriangle, Trash2, Plus, Minus, CreditCard } from 'lucide-react';
import { calcularEnvio } from '../utils/shippingService';

const Carrito = ({ cart, setCart, onCheckout }) => {
  const [modoEntrega, setModoEntrega] = useState('delivery');
  const [paso, setPaso] = useState('revision');
  
  // Simulamos una distancia (esto vendría del perfil del usuario en el futuro)
  const distancia = 4.2; 
  const costoEnvio = modoEntrega === 'delivery' ? calcularEnvio(distancia) : 0;

  const totalProductos = cart.reduce((acc, p) => acc + (Number(p.precioNuevo) || 0), 0);
  const totalPeso = cart.reduce((acc, p) => acc + (Number(p.peso) || 0), 0);
  const totalPagar = totalProductos + costoEnvio;

  const ajustarCantidad = (producto, accion) => {
    if (accion === 'sumar') {
      const enCarrito = cart.filter(i => i.id === producto.id).length;
      if (enCarrito < producto.stock) setCart([...cart, { ...producto, instanceId: Date.now() }]);
      else alert("Stock máximo alcanzado");
    } else {
      const idx = cart.findLastIndex(i => i.id === producto.id);
      if (idx > -1) {
        const nuevo = [...cart];
        nuevo.splice(idx, 1);
        setCart(nuevo);
      }
    }
  };

  const itemsAgrupados = cart.reduce((acc, item) => {
    if (!acc[item.id]) acc[item.id] = { ...item, cantidad: 0 };
    acc[item.id].cantidad += 1;
    return acc;
  }, {});

  return (
    <div style={cartContainer}>
      <h3 style={title}><ShoppingBag size={20} color="#e67e22" /> Tu Pedido</h3>
      
      <div style={deliverySelector}>
        <button onClick={() => setModoEntrega('delivery')} style={modoEntrega === 'delivery' ? btnActive : btnInactive}>Delivery</button>
        <button onClick={() => setModoEntrega('retiro')} style={modoEntrega === 'retiro' ? btnActive : btnInactive}>Retiro</button>
      </div>

      {modoEntrega === 'delivery' && (
        <div style={totalPeso > 15 ? errorBox : weightBox}>
          <AlertTriangle size={14} /> 
          <span>Peso: {totalPeso.toFixed(3)}kg / 15kg</span>
        </div>
      )}

      {paso === 'revision' ? (
        <>
          <div style={listStyle}>
            {Object.values(itemsAgrupados).map(item => (
              <div key={item.id} style={itemRow}>
                <div style={{flex: 1}}><div style={itemName}>{item.producto}</div><div style={itemSubtext}>${item.precioNuevo}</div></div>
                <div style={qtyControls}>
                  <button style={btnQty} onClick={() => ajustarCantidad(item, 'restar')}><Minus size={12} /></button>
                  <span style={qtyNum}>{item.cantidad}</span>
                  <button style={btnQty} onClick={() => ajustarCantidad(item, 'sumar')}><Plus size={12} /></button>
                </div>
                <Trash2 size={16} color="#ef4444" cursor="pointer" onClick={() => setCart(cart.filter(i => i.id !== item.id))} />
              </div>
            ))}
          </div>
          <div style={totalBox}>
            {modoEntrega === 'delivery' && <div style={rowTotal}><span>Envío ({distancia}km)</span><span>${costoEnvio}</span></div>}
            <div style={{...rowTotal, fontWeight: 'bold', fontSize: '1.2rem', color: '#e67e22'}}><span>Total</span><span>${totalPagar}</span></div>
          </div>
          <button disabled={modoEntrega === 'delivery' && totalPeso > 15} onClick={() => setPaso('pago')} style={btnPrimario}>Pagar Online</button>
        </>
      ) : (
        <div style={{textAlign: 'center'}}>
          <CreditCard size={40} color="#e67e22" style={{marginBottom: '15px'}} />
          <p>Confirmar pago de <strong>${totalPagar}</strong></p>
          <button onClick={() => onCheckout(totalPagar)} style={btnPrimario}>Finalizar Compra</button>
          <button onClick={() => setPaso('revision')} style={btnVolver}>Volver</button>
        </div>
      )}
    </div>
  );
};

// Estilos rápidos para Carrito
const cartContainer = { background: 'white', padding: '20px', borderRadius: '20px', boxShadow: '0 8px 30px rgba(0,0,0,0.1)', width: '350px' };
const title = { display: 'flex', alignItems: 'center', gap: '8px', fontSize: '1.1rem' };
const deliverySelector = { display: 'flex', background: '#f1f5f9', padding: '4px', borderRadius: '10px', margin: '15px 0' };
const btnActive = { flex: 1, padding: '8px', border: 'none', background: '#1e293b', color: 'white', borderRadius: '8px', fontWeight: 'bold' };
const btnInactive = { flex: 1, background: 'none', border: 'none', color: '#64748b' };
const weightBox = { background: '#f0fdf4', padding: '10px', borderRadius: '10px', fontSize: '0.8rem', display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '10px' };
const errorBox = { ...weightBox, background: '#fef2f2', color: '#ef4444' };
const listStyle = { borderTop: '1px solid #f1f5f9', paddingTop: '10px' };
const itemRow = { display: 'flex', alignItems: 'center', marginBottom: '12px' };
const itemName = { fontWeight: 'bold', fontSize: '0.85rem' };
const itemSubtext = { fontSize: '0.75rem', color: '#94a3b8' };
const qtyControls = { display: 'flex', alignItems: 'center', background: '#f8fafc', padding: '4px', borderRadius: '8px', margin: '0 10px' };
const btnQty = { border: 'none', background: 'white', cursor: 'pointer', padding: '2px' };
const qtyNum = { margin: '0 8px', fontSize: '0.8rem', fontWeight: 'bold' };
const totalBox = { borderTop: '2px dashed #f1f5f9', padding: '15px 0' };
const rowTotal = { display: 'flex', justifyContent: 'space-between', marginBottom: '5px' };
const btnPrimario = { width: '100%', padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };
const btnVolver = { background: 'none', border: 'none', marginTop: '10px', color: '#94a3b8', cursor: 'pointer' };

export default Carrito;
